    ToggleAutoStart(bool),
    ToggleContextMenu(bool),
    GlobalHotkeyChanged(String),
    PollHotkey,
}

pub struct App {
    state: Option<Arc<AppState>>,
    error: Option<String>,
    search_error: Option<String>,
    search_query: String,
    results: Vec<FileItem>,
    selected_index: Option<usize>,
