use crate::error::{FlashError, Result};
use crate::parsers::ParsedDocument;
use memmap2::Mmap;
use std::fs::File;
use std::io::{BufReader, Read};
use std::path::Path;

/// Threshold for using memory mapping (files larger than this will be memory-mapped)
const MMAP_THRESHOLD: u64 = 1024 * 1024; // 1MB
/// Maximum file size to parse (prevent DOS)
const MAX_FILE_SIZE: u64 = 100 * 1024 * 1024; // 100MB

/// Parse plain text files (TXT, MD, code files)
/// Uses memory mapping for large files to reduce memory usage
pub fn parse_text(path: &Path) -> Result<ParsedDocument> {
    let metadata = std::fs::metadata(path).map_err(FlashError::Io)?;

    let file_size = metadata.len();

    // Security: skip extremely large files
    if file_size > MAX_FILE_SIZE {
        return Err(FlashError::parse(
            path,
            format!(
                "File too large: {} bytes (max: {})",
                file_size, MAX_FILE_SIZE
            ),
        ));
    }

    // Choose parsing strategy based on file size
    let content = if file_size > MMAP_THRESHOLD {
        parse_with_mmap(path)?
    } else {
        parse_with_buffer(path)?
    };

    // Extract title from first non-empty line
    let title = extract_title(&content);

    Ok(ParsedDocument {
        path: path.to_string_lossy().to_string(),
        content,
        title,
    })
}

/// Parse small files using buffered reader (faster for small files)
fn parse_with_buffer(path: &Path) -> Result<String> {
    let file = File::open(path).map_err(FlashError::Io)?;

    let mut content = String::new();
    BufReader::new(file)
        .read_to_string(&mut content)
        .map_err(FlashError::Io)?;

    Ok(content)
}

/// Parse large files using memory mapping (zero-copy, better for large files)
fn parse_with_mmap(path: &Path) -> Result<String> {
    let file = File::open(path)
        .map_err(|e| FlashError::parse(path, format!("Failed to open file: {}", e)))?;

    // SAFETY: Memory mapping a file is unsafe because another process could modify it
    // while we are reading, potentially violating Rust's memory safety guarantees.
    // We only read the data and accept this risk for performance reasons.
    let mmap = unsafe { Mmap::map(&file).map_err(|e| FlashError::Io(std::io::Error::other(e)))? };

    // Use from_utf8_lossy to handle potential invalid UTF-8 sequences without erroring out
    // and to avoid an explicit intermediate Vec allocation (mmap.to_vec()).
    // This returns Cow<str>, into_owned() converts to String.
    Ok(String::from_utf8_lossy(&mmap).into_owned())
}

/// Extract title from first non-empty line
fn extract_title(content: &str) -> Option<String> {
    content
        .lines()
        .find(|line| !line.trim().is_empty())
        .map(|line| {
            // Remove markdown heading markers if present
            let trimmed = line.trim();
            if let Some(stripped) = trimmed.strip_prefix("# ") {
                stripped.to_string()
            } else if let Some(stripped) = trimmed.strip_prefix("## ") {
                stripped.to_string()
            } else if let Some(stripped) = trimmed.strip_prefix("### ") {
                stripped.to_string()
            } else {
                trimmed.to_string()
            }
        })
        .filter(|line| line.len() < 200) // Sanity check: don't use entire paragraphs
}

