            let mut doc_batch: Vec<(crate::parsers::ParsedDocument, u64, u64)> =
                Vec::with_capacity(BATCH_SIZE);
            let mut meta_batch: Vec<(String, u64, u64, [u8; 32])> = Vec::with_capacity(BATCH_SIZE);
            let mut processed: usize = 0;

