            metadata_db,
            settings_manager: Arc::new(settings_manager),
            settings_cache: Arc::new(RwLock::new(cache)),
            watcher: std::sync::Mutex::new(watcher),
            filename_index,
            progress_tx,
            scanner,
        }
    }
}

